import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
  options: any,
  policyName: string
) {
  const runId = process.env.ZEALT_RUN_ID;
  const allowedOrigin = `https://example-${runId}.com`;
  const requestOrigin = request.headers.get("origin");

  // Handle Preflight
  if (request.method === "OPTIONS") {
    const headers = new Headers();
    if (requestOrigin === allowedOrigin) {
      headers.set("Access-Control-Allow-Origin", allowedOrigin);
    } else {
      // If origin doesn't match, we still need to be careful. 
      // The requirement says "Response Header Access-Control-Allow-Origin should NOT be https://evil.com"
      // We can just not set it.
    }
    headers.set("Access-Control-Allow-Methods", "GET, OPTIONS");
    headers.set("Access-Control-Allow-Headers", "Content-Type, Authorization");
    return new Response(null, {
      status: 204,
      headers,
    });
  }

  const response = await context.next();

  if (requestOrigin === allowedOrigin) {
    response.headers.set("Access-Control-Allow-Origin", allowedOrigin);
  }

  return response;
}
